    }

    // =====================================================================
    // Recorded-input behavior.
    // =====================================================================

    [Fact]
    public void Browse_Records_The_Provided_RelativePath()
    {
        var fake = new FakeFileService();

        fake.Browse("docs/sub");

        Assert.Equal("docs/sub", fake.BrowsePath);
